function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

export default function deepMerge<T extends Record<string, unknown>>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key as keyof typeof source];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}-${max}] in "${context}"`);
  }
}

function parseSimple(token: string, min: number, max: number): number[] {
  // Wildcard
  if (token === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or start-end/n or start/n
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const rangeStr = token.slice(0, slashIdx);
    const step = parseInt(token.slice(slashIdx + 1), 10);

    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value in "${token}"`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = min;
      end = max;
    } else if (rangeStr.includes("-")) {
      const [s, e] = rangeStr.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new RangeError(`Invalid range in "${token}"`);
      assertInRange(s, min, max, token);
      assertInRange(e, min, max, token);
      if (s > e) throw new RangeError(`Range start exceeds end in "${token}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangeStr, 10);
      if (isNaN(start)) throw new RangeError(`Invalid value in "${token}"`);
      assertInRange(start, min, max, token);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new RangeError(`Invalid range in "${token}"`);
    assertInRange(start, min, max, token);
    assertInRange(end, min, max, token);
    if (start > end) throw new RangeError(`Range start exceeds end in "${token}"`);
    return rangeArray(start, end);
  }

  // Single value
  const value = parseInt(token, 10);
  if (isNaN(value)) throw new RangeError(`Invalid token "${token}"`);
  assertInRange(value, min, max, token);
  return [value];
}

function parseField(expression: string, min: number, max: number): number[] {
  if (expression.includes(",")) {
    const values = expression
      .split(",")
      .flatMap(part => parseSimple(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }
  return parseSimple(expression.trim(), min, max);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute:     parseField(minuteExpr,     ...FIELD_RANGES.minute),
    hour:       parseField(hourExpr,       ...FIELD_RANGES.hour),
    dayOfMonth: parseField(dayOfMonthExpr, ...FIELD_RANGES.dayOfMonth),
    month:      parseField(monthExpr,      ...FIELD_RANGES.month),
    dayOfWeek:  parseField(dayOfWeekExpr,  ...FIELD_RANGES.dayOfWeek),
  };
}

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseField(token: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard
  if (token === "*") {
    return range(min, max);
  }

  // Step: */step or start-end/step
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}"`);
    }
    let start: number;
    let end: number;
    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      assertInRange(lo, min, max, token);
      assertInRange(hi, min, max, token);
      if (lo > hi) throw new RangeError(`Invalid range "${rangePart}"`);
      start = lo;
      end = hi;
    } else {
      start = parseInt(rangePart, 10);
      assertInRange(start, min, max, token);
      end = max;
    }
    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: start-end
  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) throw new RangeError(`Invalid range "${token}"`);
    const lo = parseInt(parts[0], 10);
    const hi = parseInt(parts[1], 10);
    if (isNaN(lo) || isNaN(hi)) throw new RangeError(`Invalid range "${token}"`);
    assertInRange(lo, min, max, token);
    assertInRange(hi, min, max, token);
    if (lo > hi) throw new RangeError(`Range start ${lo} exceeds end ${hi}`);
    return range(lo, hi);
  }

  // Comma-separated list
  if (token.includes(",")) {
    const values = token.split(",").map((v) => {
      const n = parseInt(v.trim(), 10);
      if (isNaN(n)) throw new RangeError(`Invalid list value "${v}" in "${token}"`);
      assertInRange(n, min, max, token);
      return n;
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const n = parseInt(token, 10);
  if (isNaN(n)) throw new RangeError(`Invalid cron field value "${token}"`);
  assertInRange(n, min, max, token);
  return [n];
}

export default function parseCron(expression: string): CronSchedule {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${fields.length}`);
  }

  const [minuteTokens, hourTokens, domTokens, monthTokens, dowTokens] = fields;

  const dayOfWeekRaw = parseField(dowTokens, FIELD_CONFIGS[4]);
  // Normalize: treat 7 as 0 (both represent Sunday)
  const dayOfWeek = [...new Set(dayOfWeekRaw.map((v) => (v === 7 ? 0 : v)))].sort(
    (a, b) => a - b,
  );

  return {
    minute: parseField(minuteTokens, FIELD_CONFIGS[0]),
    hour: parseField(hourTokens, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domTokens, FIELD_CONFIGS[2]),
    month: parseField(monthTokens, FIELD_CONFIGS[3]),
    dayOfWeek,
  };
}

export default function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];
    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

