interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(start: number, end: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): number {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of valid range [${min}, ${max}] in "${context}"`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step with range or wildcard: "*/n" or "a-b/n"
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const step = parseInt(segment.slice(slashIdx + 1), 10);
    if (!Number.isInteger(step) || step < 1) {
      throw new Error(`Invalid step value in "${segment}"`);
    }
    const rangePart = segment.slice(0, slashIdx);
    if (rangePart === "*") {
      return rangeArray(min, max, step);
    }
    if (rangePart.includes("-")) {
      const [a, b] = rangePart.split("-").map((v) => assertInRange(parseInt(v, 10), min, max, segment));
      if (a > b) throw new RangeError(`Invalid range "${rangePart}": start > end`);
      return rangeArray(a, b, step);
    }
    const start = assertInRange(parseInt(rangePart, 10), min, max, segment);
    return rangeArray(start, max, step);
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range: "a-b"
  if (segment.includes("-")) {
    const [aStr, bStr] = segment.split("-");
    const a = assertInRange(parseInt(aStr, 10), min, max, segment);
    const b = assertInRange(parseInt(bStr, 10), min, max, segment);
    if (a > b) throw new RangeError(`Invalid range "${segment}": start > end`);
    return rangeArray(a, b);
  }

  // Single value
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: "${segment}"`);
  return [assertInRange(value, min, max, segment)];
}

function parseField(field: string, min: number, max: number): number[] {
  const segments = field.split(",");
  const values = segments.flatMap((seg) => parseSegment(seg.trim(), min, max));
  // Deduplicate and sort
  return [...new Set(values)].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${parts.length}`);
  }

  const fieldNames: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return fieldNames.reduce((acc, name, i) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(parts[i], min, max);
    return acc;
  }, {} as CronExpression);
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const FIELDS: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

const buildRange = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const assertInRange = (value: number, min: number, max: number, context: string): void => {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of valid range [${min}, ${max}] in field expression: "${context}"`);
  }
};

const parseField = (expr: string, field: FieldName): number[] => {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr.includes("/")) {
    const slashIndex = expr.indexOf("/");
    const rangePart = expr.slice(0, slashIndex);
    const stepStr = expr.slice(slashIndex + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in field expression: "${expr}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in: "${expr}"`);
        assertInRange(s, min, max, expr);
        assertInRange(e, min, max, expr);
        start = s;
        end = e;
      } else {
        const s = parseInt(rangePart, 10);
        if (isNaN(s)) throw new Error(`Invalid step base in: "${expr}"`);
        assertInRange(s, min, max, expr);
        start = s;
      }
    }

    if (start > end) throw new Error(`Range start exceeds end in: "${expr}"`);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  if (expr === "*") {
    return buildRange(min, max);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${expr}"`);
    assertInRange(start, min, max, expr);
    assertInRange(end, min, max, expr);
    if (start > end) throw new Error(`Range start exceeds end in: "${expr}"`);
    return buildRange(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value in field expression: "${expr}"`);
  assertInRange(value, min, max, expr);
  return [value];
};

export default function parseCron(cronExpression: string): CronExpression {
  const parts = cronExpression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields but got ${parts.length} in "${cronExpression}"`
    );
  }

  return Object.fromEntries(
    FIELDS.map((field, i) => [field, parseField(parts[i], field)])
  ) as CronExpression;
}

