  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  assertInRange(value, min, max, field);
  return [value];
}

function parseField(expression: string, min: number, max: number, field: string): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max, field)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}. Format: minute hour dayOfMonth month dayOfWeek`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute, fieldNames[0]),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour, fieldNames[1]),
    dayOfMonth: parseField(domExpr, ...FIELD_RANGES.dayOfMonth, fieldNames[2]),
    month: parseField(monthExpr, ...FIELD_RANGES.month, fieldNames[3]),
    dayOfWeek: parseField(dowExpr, ...FIELD_RANGES.dayOfWeek, fieldNames[4]),
  };
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function assertInRange(values: number[], min: number, max: number, field: string): void {
  for (const v of values) {
    if (v < min || v > max) {
      throw new RangeError(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
}

function parseField(token: string, min: number, max: number, field: string): number[] {
  // Comma-separated list
  if (token.includes(",")) {
    const values = token.split(",").flatMap((t) => parseField(t.trim(), min, max, field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step value: */N or start-end/N
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step "${stepStr}" in field "${field}"`);

    let from = min;
    let to = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        from = parseInt(startStr, 10);
        to = parseInt(endStr, 10);
        if (isNaN(from) || isNaN(to)) throw new SyntaxError(`Invalid range "${rangePart}" in field "${field}"`);
      } else {
        from = parseInt(rangePart, 10);
        if (isNaN(from)) throw new SyntaxError(`Invalid value "${rangePart}" in field "${field}"`);
      }
    }

    assertInRange([from, to], min, max, field);
    return rangeArray(from, to, step);
  }

  // Wildcard
  if (token === "*") return rangeArray(min, max);

  // Range: start-end
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const from = parseInt(startStr, 10);
    const to = parseInt(endStr, 10);
    if (isNaN(from) || isNaN(to)) throw new SyntaxError(`Invalid range "${token}" in field "${field}"`);
    if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to} in field "${field}"`);
    assertInRange([from, to], min, max, field);
    return rangeArray(from, to);
  }

  // Single number
  const value = parseInt(token, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid token "${token}" in field "${field}"`);
  assertInRange([value], min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = [
    minuteToken,
    hourToken,
    domToken,
    monthToken,
    dowToken,
  ].map((token, i) => {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    return parseField(token, min, max, name);
  });

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function rangeArray(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function clamp(value: number, min: number, max: number, label: string): number {
  if (value < min || value > max)
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${label}"`);
  return value;
}

function parseField(field: string, label: keyof CronExpression): number[] {
  const [min, max] = FIELD_RANGES[label];

  // Comma-separated list — recurse on each part
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), label));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") return rangeArray(min, max);

  // Step value: */n or start/n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new RangeError(`Invalid step value "${stepStr}" in field "${label}"`);

    let from = min;
    let to = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        from = clamp(lo, min, max, label);
        to = clamp(hi, min, max, label);
      } else {
        from = clamp(parseInt(rangePart, 10), min, max, label);
      }
    }

    const result: number[] = [];
    for (let v = from; v <= to; v += step) result.push(v);
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [loStr, hiStr] = field.split("-");
    const lo = clamp(parseInt(loStr, 10), min, max, label);
    const hi = clamp(parseInt(hiStr, 10), min, max, label);
    return rangeArray(lo, hi);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new TypeError(`Invalid value "${field}" for field "${label}"`);
  return [clamp(value, min, max, label)];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  return {
    minute: parseField(minuteStr, "minute"),
    hour: parseField(hourStr, "hour"),
    dayOfMonth: parseField(domStr, "dayOfMonth"),
    month: parseField(monthStr, "month"),
    dayOfWeek: parseField(dowStr, "dayOfWeek"),
  };
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = part.match(/^(\*|(\d+)-(\d+)|\d+)\/(\d+)$/);
    if (stepMatch) {
      const step = parseInt(stepMatch[4], 10);
      if (step <= 0) throw new RangeError(`Step value must be positive, got ${step}`);

      let start: number;
      let end: number;

      if (stepMatch[1] === "*") {
        start = min;
        end = max;
      } else if (stepMatch[2] !== undefined) {
        start = clamp(parseInt(stepMatch[2], 10), min, max);
        end   = clamp(parseInt(stepMatch[3], 10), min, max);
        if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
      } else {
        start = clamp(parseInt(stepMatch[1], 10), min, max);
        end = max;
      }

      for (let i = start; i <= end; i += step) results.add(i);
      continue;
    }

    const rangeMatch = part.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = clamp(parseInt(rangeMatch[1], 10), min, max);
      const end   = clamp(parseInt(rangeMatch[2], 10), min, max);
      if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    if (/^\d+$/.test(part)) {
      results.add(clamp(parseInt(part, 10), min, max));
      continue;
    }

    throw new SyntaxError(`Unrecognized cron field expression: "${part}"`);
  }

  return [...results].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, name, index) => {
    const { min, max } = FIELD_RANGES[name];
    acc[name] = parseField(parts[index], min, max);
    return acc;
  }, {} as CronFields);
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

export default deepMerge;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | Array<unknown>;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },
  { min: 0, max: 23 },
  { min: 1, max: 31 },
  { min: 1, max: 12 },
  { min: 0, max: 6 },
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function rangeArray(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInBounds(value: number, min: number, max: number, label: string): void {
  if (value < min || value > max) {
    throw new RangeError(`${label} value ${value} is out of range [${min}, ${max}]`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n, start/n, or start-end/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new TypeError(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (base === "*") {
      start = min;
      end = max;
    } else if (base.includes("-")) {
      const [s, e] = base.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new TypeError(`Invalid range in step: "${base}"`);
      assertInBounds(s, min, max, "Range start");
      assertInBounds(e, min, max, "Range end");
      if (s > e) throw new RangeError(`Range start ${s} exceeds end ${e}`);
      start = s;
      end = e;
    } else {
      start = parseInt(base, 10);
      if (isNaN(start)) throw new TypeError(`Invalid step base: "${base}"`);
      assertInBounds(start, min, max, "Step base");
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new TypeError(`Invalid range: "${segment}"`);
    assertInBounds(start, min, max, "Range start");
    assertInBounds(end, min, max, "Range end");
    if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new TypeError(`Invalid value: "${segment}"`);
  assertInBounds(value, min, max, "Value");
  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  if (field.includes(",")) {
    const seen = new Set<number>();
    for (const segment of field.split(",")) {
      for (const v of parseSegment(segment.trim(), min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }
  return parseSegment(field, min, max);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new TypeError(`Expected 5 cron fields, got ${parts.length}: "${expression}"`);
  }

  return Object.fromEntries(
    FIELD_NAMES.map((name, i) => [name, parseField(parts[i], FIELD_CONFIGS[i].min, FIELD_CONFIGS[i].max)])
  ) as CronFields;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj) as string;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = (obj as Record<string, unknown>)[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as string)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export default function deepMerge<T extends PlainObject>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key as keyof typeof source];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (sourceVal !== undefined) {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];
    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }
  return result;
}

export default flattenObject;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function expandRange(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(field: string, min: number, max: number): number[] {
  // Wildcard
  if (field === "*") {
    return expandRange(min, max);
  }

  // Step with wildcard: */n
  const stepWildcardMatch = field.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new RangeError(`Step value must be positive, got ${step}`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) {
      values.push(i);
    }
    return values;
  }

  // Comma-separated list
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Range with optional step: n-m or n-m/s
  const rangeMatch = field.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const rangeMin = clamp(parseInt(rangeMatch[1], 10), min, max);
    const rangeMax = clamp(parseInt(rangeMatch[2], 10), min, max);
    if (rangeMin > rangeMax) {
      throw new RangeError(`Range start ${rangeMin} must be <= range end ${rangeMax}`);
    }
    const step = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;
    if (step <= 0) throw new RangeError(`Step value must be positive, got ${step}`);
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const numMatch = field.match(/^(\d+)$/);
  if (numMatch) {
    const value = clamp(parseInt(numMatch[1], 10), min, max);
    // Normalize dayOfWeek: treat 7 as 0 (both mean Sunday)
    return [value];
  }

  throw new SyntaxError(`Unrecognized cron field expression: "${field}"`);
}

function normalizeDayOfWeek(values: number[]): number[] {
  return Array.from(
    new Set(values.map((v) => (v === 7 ? 0 : v)))
  ).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const parts = trimmed.split(" ");

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    const values = parseField(parts[i], min, max);
    result[name] = name === "dayOfWeek" ? normalizeDayOfWeek(values) : values;
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }
  return result;
}

