export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, min: number, max: number): number[] => {
  // Comma-separated list
  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [base, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value: "${stepStr}"`);
    }
    const [rangeMin, rangeMax] =
      base === "*" ? [min, max] : parseRange(base, min, max);
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(clamp(i, min, max));
    }
    return values;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [start, end] = parseRange(field, min, max);
    return range(start, end);
  }

  // Single number
  const num = parseInt(field, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid cron field value: "${field}"`);
  }
  return [clamp(num, min, max)];
};

const parseRange = (field: string, min: number, max: number): [number, number] => {
  const parts = field.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(`Invalid range expression: "${field}"`);
  }
  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end)) {
    throw new SyntaxError(`Invalid range values in: "${field}"`);
  }
  clamp(start, min, max);
  clamp(end, min, max);
  if (start > end) {
    throw new RangeError(`Range start ${start} is greater than end ${end}`);
  }
  return [start, end];
};

const parseCron = (expression: string): CronExpression => {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields in cron expression, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];
  const fieldValues = [minuteField, hourField, domField, monthField, dowField];

  return fieldKeys.reduce((acc, key, i) => {
    const [min, max] = FIELD_RANGES[key];
    acc[key] = parseField(fieldValues[i], min, max);
    return acc;
  }, {} as CronExpression);
};

