export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseField(expr: string, min: number, max: number): number[] {
  const results = new Set<number>();

  for (const part of expr.split(",")) {
    if (part === "*") {
      for (let i = min; i <= max; i++) results.add(i);
    } else if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      for (let i = min; i <= max; i += step) results.add(i);
    } else if (part.includes("/")) {
      const [rangePart, stepPart] = part.split("/");
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      const [startStr, endStr] = rangePart.includes("-")
        ? rangePart.split("-")
        : [rangePart, String(max)];
      const start = clamp(parseInt(startStr, 10), min, max);
      const end   = clamp(parseInt(endStr, 10), min, max);
      if (start > end) throw new RangeError(`Invalid range: ${part}`);
      for (let i = start; i <= end; i += step) results.add(i);
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = clamp(parseInt(startStr, 10), min, max);
      const end   = clamp(parseInt(endStr, 10), min, max);
      if (start > end) throw new RangeError(`Invalid range: ${part}`);
      for (let i = start; i <= end; i++) results.add(i);
    } else {
      const value = parseInt(part, 10);
      if (isNaN(value)) throw new Error(`Invalid value: ${part}`);
      results.add(clamp(value, min, max));
    }
  }

  return [...results].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs  = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return Object.fromEntries(
    fields.map((field, i) => {
      const { min, max } = FIELD_RANGES[field];
      return [field, parseField(exprs[i], min, max)];
    })
  ) as CronFields;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

function parseField(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  const allValues = (): number[] =>
    Array.from({ length: max - min + 1 }, (_, i) => min + i);

  // Comma-separated list — recurse on each part
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return allValues();
  }

  // Step value: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value in expression: "${expr}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      rangeMin = parseInt(startStr, 10);
      rangeMax = parseInt(endStr, 10);
    } else {
      rangeMin = parseInt(rangePart, 10);
      rangeMax = max;
    }

    if (isNaN(rangeMin) || isNaN(rangeMax)) {
      throw new Error(`Invalid range in expression: "${expr}"`);
    }

    validateRange(rangeMin, rangeMax, min, max, expr);

    const result: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in expression: "${expr}"`);
    }

    validateRange(start, end, min, max, expr);

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value in expression: "${expr}"`);
  }

  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}] in expression: "${expr}"`
    );
  }

  return [value];
}

function validateRange(
  start: number,
  end: number,
  min: number,
  max: number,
  expr: string
): void {
  if (start < min || start > max || end < min || end > max) {
    throw new Error(
      `Range out of bounds [${min}, ${max}] in expression: "${expr}"`
    );
  }
  if (start > end) {
    throw new Error(`Start of range exceeds end in expression: "${expr}"`);
  }
}

function parseCron(cronExpression: string): CronFields {
  const parts = cronExpression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const [minuteConfig, hourConfig, domConfig, monthConfig, dowConfig] =
    FIELD_CONFIGS;

  return {
    minute: parseField(minuteExpr, minuteConfig),
    hour: parseField(hourExpr, hourConfig),
    dayOfMonth: parseField(domExpr, domConfig),
    month: parseField(monthExpr, monthConfig),
    dayOfWeek: parseField(dowExpr, dowConfig),
  };
}

