export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const validateValue = (value: number, min: number, max: number, field: string): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
  return value;
};

const parseSegment = (segment: string, min: number, max: number, field: string): number[] => {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step value (*/n or start/n)
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${field}"`);
    }
    const start = left === "*" ? min : parseInt(left, 10);
    if (isNaN(start)) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${field}"`);
    }
    validateValue(start, min, max, field);
    return range(start, max).filter((v) => (v - start) % step === 0);
  }

  // Range (start-end)
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in field "${field}"`);
    }
    validateValue(start, min, max, field);
    validateValue(end, min, max, field);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  return [validateValue(value, min, max, field)];
};

const parseField = (expression: string, min: number, max: number, field: string): number[] => {
  const values = expression
    .split(",")
    .flatMap((segment) => parseSegment(segment.trim(), min, max, field));

  return [...new Set(values)].sort((a, b) => a - b);
};

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];

  return Object.fromEntries(
    fieldNames.map((name, i) => {
      const [min, max] = FIELD_RANGES[name];
      return [name, parseField(fields[i], min, max, name)];
    })
  ) as CronExpression;
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

function deepMerge(
  target: Record<string, unknown>,
  source: Record<string, unknown>
): Record<string, unknown> {
  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    const sourceVal = source[key];
    const targetVal = result[key];

    if (Array.isArray(sourceVal) && Array.isArray(targetVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(sourceVal) && isPlainObject(targetVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result;
}

export default deepMerge;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseField(token: string, min: number, max: number): number[] {
  // Wildcard
  if (token === "*") return rangeArray(min, max);

  // Step: */n or a-b/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${stepStr}`);
    const [from, to] = rangePart === "*"
      ? [min, max]
      : rangePart.split("-").map(Number);
    if (isNaN(from) || isNaN(to) || from < min || to > max || from > to)
      throw new Error(`Invalid range in step expression: ${rangePart}`);
    return rangeArray(from, to, step);
  }

  // Comma-separated list
  if (token.includes(",")) {
    const values = token.split(",").flatMap(t => parseField(t.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Range: a-b
  if (token.includes("-")) {
    const [fromStr, toStr] = token.split("-");
    const from = parseInt(fromStr, 10);
    const to   = parseInt(toStr,   10);
    if (isNaN(from) || isNaN(to) || from < min || to > max || from > to)
      throw new Error(`Invalid range: ${token} (valid: ${min}-${max})`);
    return rangeArray(from, to);
  }

  // Single number
  const n = parseInt(token, 10);
  if (isNaN(n) || n < min || n > max)
    throw new Error(`Value ${token} out of range ${min}-${max}`);
  return [n];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(`Expected 5 fields, got ${parts.length}`);

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fieldNames.reduce((acc, field, i) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = parseField(parts[i], min, max);
    return acc;
  }, {} as CronFields);
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge(target: unknown, source: unknown): unknown {
  if (Array.isArray(target) && Array.isArray(source)) {
    return [...target, ...source];
  }

  if (isPlainObject(target) && isPlainObject(source)) {
    const result: PlainObject = { ...target };
    for (const key of Object.keys(source)) {
      result[key] = Object.prototype.hasOwnProperty.call(target, key)
        ? deepMerge(target[key], source[key])
        : source[key];
    }
    return result;
  }

  return source === undefined ? target : source;
}

export default deepMerge;

export interface CronExpression {
  minute: number[];
