  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      start = clamp(s, min, max);
      end = clamp(e, min, max);
      if (start > end) throw new Error(`Invalid range: "${rangePart}"`);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) throw new Error(`Invalid range: "${segment}"`);
    return range(start, end);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").map((part) => {
      const n = parseInt(part.trim(), 10);
      if (isNaN(n)) throw new Error(`Invalid value: "${part}"`);
      return clamp(n, min, max);
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid cron field: "${segment}"`);
  return [clamp(n, min, max)];
};

const parseCron = (expression: string): CronExpression => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldNames = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];
  const fieldValues = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronExpression;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const value = fieldValues[i];
    result[name] = parseSegment(value, FIELD_CONFIGS[name]);
  }

  return result;
};

export default parseCron;

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }

  return result;
}

