type FieldDef = { min: number; max: number };

const FIELD_DEFS: FieldDef[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

function range(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseSegment(segment: string, def: FieldDef): number[] {
  // Step: */step or start-end/step
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: ${stepStr}`);
    if (left === "*") return range(def.min, def.max, step);
    if (left.includes("-")) {
      const [startStr, endStr] = left.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${left}`);
      return range(start, end, step);
    }
    throw new Error(`Invalid step expression: ${segment}`);
  }

  // Wildcard
  if (segment === "*") return range(def.min, def.max);

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start < def.min || end > def.max || start > end)
      throw new Error(`Range out of bounds: ${segment} (valid: ${def.min}-${def.max})`);
    return range(start, end);
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  if (val < def.min || val > def.max)
    throw new Error(`Value ${val} out of bounds (valid: ${def.min}-${def.max})`);
  return [val];
}

function parseField(field: string, def: FieldDef): number[] {
  // Comma-separated list
  const segments = field.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), def)) {
      if (v < def.min || v > def.max)
        throw new Error(`Value ${v} out of bounds (valid: ${def.min}-${def.max})`);
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

