const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  const validate = (n: number): number => {
    if (n < min || n > max) {
      throw new RangeError(`Value ${n} is out of range [${min}, ${max}]`);
    }
    return n;
  };

  for (const part of field.split(",")) {
    if (part === "*") {
      rangeArray(min, max).forEach(v => values.add(v));
      continue;
    }

    if (part.startsWith("*/")) {
      const step = parseInt(part.slice(2), 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      for (let i = min; i <= max; i += step) values.add(i);
      continue;
    }

    if (part.includes("/")) {
      const [rangePart, stepStr] = part.split("/");
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${part}`);
      const [startStr, endStr] = rangePart.split("-");
      const start = validate(parseInt(startStr, 10));
      const end = endStr !== undefined ? validate(parseInt(endStr, 10)) : max;
      if (start > end) throw new RangeError(`Invalid range: ${rangePart}`);
      for (let i = start; i <= end; i += step) values.add(i);
      continue;
    }

    if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = validate(parseInt(startStr, 10));
      const end = validate(parseInt(endStr, 10));
      if (start > end) throw new RangeError(`Invalid range: ${part}`);
      rangeArray(start, end).forEach(v => values.add(v));
      continue;
    }

    const n = parseInt(part, 10);
    if (isNaN(n)) throw new Error(`Invalid cron field value: ${part}`);
    values.add(validate(n));
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];
  const result = {} as CronExpression;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(fields[i], min, max);
  }

  return result;
}

