  month:      [1,  12],
  dayOfWeek:  [0,   7],
};

function parseField(field: string, min: number, max: number): number[] {
  if (field.includes(',')) {
    const values = field
      .split(',')
      .flatMap(part => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field.includes('/')) {
    const slashIdx = field.indexOf('/');
    const rangePart = field.slice(0, slashIdx);
    const stepStr = field.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start = min;
    let end = max;

    if (rangePart !== '*') {
      if (rangePart.includes('-')) {
        const [s, e] = rangePart.split('-').map(v => parseInt(v, 10));
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
        if (isNaN(start) || start < min || start > max) {
          throw new Error(`Step start "${rangePart}" out of range [${min}, ${max}]`);
        }
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  if (field.includes('-')) {
    const dashIdx = field.indexOf('-');
    const start = parseInt(field.slice(0, dashIdx), 10);
    const end = parseInt(field.slice(dashIdx + 1), 10);

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: "${field}"`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(`Range "${field}" out of bounds [${min}, ${max}]`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  if (field === '*') {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid field value: "${field}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
}

