  max: number;
  name: string;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 6, name: "dayOfWeek" },
];

function parseField(field: string, config: FieldConfig): number[] {
  const { min, max, name } = config;

  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (field === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (field.includes("/")) {
    const [rangeOrWild, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepStr}" in field "${name}"`);
    }

    let start = min;
    let end = max;

    if (rangeOrWild !== "*") {
      if (rangeOrWild.includes("-")) {
        const [s, e] = rangeOrWild.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangeOrWild, 10);
      }
      if (isNaN(start) || start < min || start > max) {
        throw new Error(`Step start "${rangeOrWild}" out of range for field "${name}" [${min}-${max}]`);
      }
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  if (field.includes("-")) {
    const parts = field.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range "${field}" in field "${name}"`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Non-numeric range "${field}" in field "${name}"`);
    }
    if (start > end) {
      throw new Error(`Range start ${start} exceeds end ${end} in field "${name}"`);
    }
    if (start < min || end > max) {
      throw new Error(`Range "${field}" out of bounds for field "${name}" [${min}-${max}]`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  const num = parseInt(field, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid value "${field}" in field "${name}"`);
  }
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of range for field "${name}" [${min}-${max}]`);
  }
  return [num];
}

