export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function validateValue(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
}

function parseField(expr: string, field: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma-separated list — parse each part recursively
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard with step: */n
  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  // Wildcard: *
  if (expr === "*") {
    return range(min, max);
  }

  // Range with optional step: a-b or a-b/n
  if (expr.includes("-")) {
    const [rangePart, stepPart] = expr.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${expr}" for field "${field}"`);
    }
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} for field "${field}"`);
    }

    validateValue(start, min, max, field);
    validateValue(end, min, max, field);

    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }

    return range(start, end).filter((v) => (v - start) % step === 0);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid expression "${expr}" for field "${field}"`);
  }
  validateValue(value, min, max, field);
  return [value];
}

