  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepPart}`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map((v) => parseInt(v, 10));
        if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${rangePart}`);
        rangeMin = lo;
        rangeMax = hi;
      } else {
        rangeMin = parseInt(rangePart, 10);
        if (isNaN(rangeMin)) throw new Error(`Invalid step base: ${rangePart}`);
        rangeMax = max;
      }
    }

    if (rangeMin < min || rangeMax > max || rangeMin > rangeMax) {
      throw new Error(`Range ${rangeMin}-${rangeMax} out of bounds [${min}-${max}]`);
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: n-m
  if (field.includes("-")) {
    const [lo, hi] = field.split("-").map((v) => parseInt(v, 10));
    if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${field}`);
    if (lo < min || hi > max || lo > hi) {
      throw new Error(`Range ${lo}-${hi} out of bounds [${min}-${max}]`);
    }
    return rangeArray(lo, hi);
  }

  // Single number
  const num = parseInt(field, 10);
  if (isNaN(num)) throw new Error(`Invalid field value: ${field}`);
  if (num < min || num > max) {
    throw new Error(`Value ${num} out of bounds [${min}-${max}]`);
  }
  return [num];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}`);
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;
  const fields = Object.keys(FIELD_RANGES) as Array<keyof CronExpression>;
  const values = [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr];

  const result = {} as CronExpression;
  for (let i = 0; i < fields.length; i++) {
    const field = fields[i];
    const [min, max] = FIELD_RANGES[field];
    result[field] = parseField(values[i], min, max);
  }

  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldRange = { min: number; max: number };

const FIELD_RANGES: Record<keyof CronExpression, FieldRange> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (field: string, { min, max }: FieldRange): number[] => {
  // Comma-separated list
  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), { min, max }))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        start = clamp(parseInt(startStr, 10), min, max);
        end = clamp(parseInt(endStr, 10), min, max);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end = clamp(parseInt(endStr, 10), min, max);
    if (start > end) {
      throw new RangeError(`Invalid range: ${start}-${end}`);
    }
    return range(start, end);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid field value: ${field}`);
  }
  return [clamp(value, min, max)];
};

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];
  const fieldValues = [minuteField, hourField, domField, monthField, dowField];

  return fields.reduce(
    (acc, key, i) => ({
      ...acc,
      [key]: parseField(fieldValues[i], FIELD_RANGES[key]),
    }),
    {} as CronExpression
  );
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive;
    }
  }
  return result;
}

export default flattenObject;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseField(expr: string, field: FieldName): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr === "*") {
    return range(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    return range(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in field "${field}": ${expr}`);
    const [startStr, endStr] = rangePart.includes("-") ? rangePart.split("-") : [rangePart, String(max)];
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range/step in field "${field}": ${expr}`);
    if (start < min || end > max) throw new Error(`Value out of range in field "${field}": ${expr}`);
    return range(start, end).filter((v) => (v - start) % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in field "${field}": ${expr}`);
    if (start < min || end > max || start > end)
      throw new Error(`Range out of bounds in field "${field}": ${expr}`);
    return range(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid value in field "${field}": ${expr}`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  return FIELD_ORDER.reduce((acc, field, i) => {
    acc[field] = parseField(fields[i], field);
    return acc;
  }, {} as CronExpression);
}

function flattenObject(
  obj: Record<string, unknown>,
  prefix = "",
  result: Record<string, unknown> = {}
): Record<string, unknown> {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];
    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }
  return result;
}

export default flattenObject;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 6 },   // dayOfWeek
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function parseField(expr: string, { min, max }: FieldConfig): number[] {
  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), { min, max }))
      .filter((v, i, arr) => arr.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${expr}`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${expr}`);
    const [rangeMin, rangeMax] = parseRange(rangePart, min, max);
    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) values.push(i);
    return values;
  }

  if (expr.includes("-")) {
    const [rangeMin, rangeMax] = parseRange(expr, min, max);
    return Array.from({ length: rangeMax - rangeMin + 1 }, (_, i) => rangeMin + i);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid cron value: ${expr}`);
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
}

function parseRange(expr: string, fieldMin: number, fieldMax: number): [number, number] {
  const parts = expr.split("-");
  if (parts.length !== 2) throw new Error(`Invalid range: ${expr}`);
  const [lo, hi] = parts.map((p) => parseInt(p.trim(), 10));
  if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range: ${expr}`);
  if (lo < fieldMin || hi > fieldMax || lo > hi) {
    throw new RangeError(`Range ${expr} invalid for bounds [${fieldMin}, ${fieldMax}]`);
  }
  return [lo, hi];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 cron fields, got ${fields.length}`);
  }

  const result = {} as CronResult;
  for (let i = 0; i < 5; i++) {
    result[FIELD_NAMES[i]] = parseField(fields[i], FIELD_CONFIGS[i]);
  }
  return result;
}

type PlainObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is PlainObject {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

export default function deepMerge<T extends PlainObject, S extends PlainObject>(
  target: T,
  source: S
): T & S {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return (isPlainObject(source) ? source : target) as T & S;
  }

  const result: PlainObject = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T & S;
}

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function expandField(expr: string, min: number, max: number): number[] {
  const all = () => Array.from({ length: max - min + 1 }, (_, i) => i + min);

  if (expr === "*") return all();

  const results = new Set<number>();

  for (const part of expr.split(",")) {
    if (part.includes("/")) {
      const [rangeStr, stepStr] = part.split("/");
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${stepStr}`);

      let start = min;
      let end = max;

      if (rangeStr !== "*") {
        if (rangeStr.includes("-")) {
          const [s, e] = rangeStr.split("-").map(Number);
          start = s;
          end = e;
        } else {
          start = parseInt(rangeStr, 10);
        }
      }

      for (let i = start; i <= end; i += step) results.add(i);
    } else if (part.includes("-")) {
      const [startStr, endStr] = part.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${part}`);
      for (let i = start; i <= end; i++) results.add(i);
    } else {
      const val = parseInt(part, 10);
      if (isNaN(val)) throw new Error(`Invalid value: ${part}`);
      results.add(val);
    }
  }

  const sorted = Array.from(results).sort((a, b) => a - b);

  for (const v of sorted) {
    if (v < min || v > max) {
      throw new Error(`Value ${v} out of range [${min}, ${max}]`);
    }
  }

  return sorted;
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const result = {} as CronResult;

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = expandField(fields[i], min, max);
  }

  return result;
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    value !== null &&
    typeof value === "object" &&
    !Array.isArray(value) &&
    (Object.getPrototypeOf(value) === Object.prototype ||
      Object.getPrototypeOf(value) === null)
  );
}

function deepMerge<T extends Record<string, unknown>>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return source as T ?? target;
  }

  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

export default deepMerge;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 7],
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function rangeArray(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for ${context}`);
  }
}

function parseSegment(segment: string, fieldName: FieldName): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new RangeError(`Invalid step value: ${stepStr}`);

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [a, b] = rangePart.split("-").map(Number);
      validateValue(a, min, max, fieldName);
      validateValue(b, min, max, fieldName);
      start = a;
      end = b;
    } else {
      start = parseInt(rangePart, 10);
      validateValue(start, min, max, fieldName);
      end = max;
    }

    const result: number[] = [];
    for (let v = start; v <= end; v += step) result.push(v);
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [a, b] = segment.split("-").map(Number);
    validateValue(a, min, max, fieldName);
    validateValue(b, min, max, fieldName);
    return rangeArray(a, b);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    return segment.split(",").map((token) => {
      const v = parseInt(token.trim(), 10);
      if (isNaN(v)) throw new RangeError(`Invalid list value: ${token}`);
      validateValue(v, min, max, fieldName);
      return v;
    });
  }

  // Single number
  const v = parseInt(segment, 10);
  if (isNaN(v)) throw new RangeError(`Invalid cron token: ${segment}`);
  validateValue(v, min, max, fieldName);
  return [v];
}

function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const values = parseSegment(parts[i], fieldName);
    // Deduplicate and sort
    result[fieldName] = [...new Set(values)].sort((a, b) => a - b);
  }

  return result;
}

export default parseCron;

interface CronFields {
