function parseField(expr: string, min: number, max: number): number[] {
  const full = Array.from({ length: max - min + 1 }, (_, i) => i + min);

  // Wildcard
  if (expr === "*") return full;

  // Step value: */n or range/n
  if (expr.includes("/")) {
    const [rangeStr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${expr}`);

    const base = rangeStr === "*" ? full : parseField(rangeStr, min, max);
    return base.filter((v) => (v - base[0]) % step === 0);
