  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const range = (lo: number, hi: number, step = 1): number[] => {
    const result: number[] = [];
    for (let i = lo; i <= hi; i += step) result.push(i);
    return result;
  };

  const validate = (n: number): number => {
    if (n < min || n > max)
      throw new RangeError(`Value ${n} is out of range [${min}, ${max}]`);
    return n;
  };

  // Comma-separated list — recurse on each part and flatten
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") return range(min, max);

  // Step: */step or start-end/step
  if (expr.includes("/")) {
    const [left, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new RangeError(`Invalid step value: ${stepStr}`);

    if (left === "*") return range(min, max, step);

    if (left.includes("-")) {
      const [lo, hi] = left.split("-").map((n) => validate(parseInt(n, 10)));
      return range(lo, hi, step);
    }

    const start = validate(parseInt(left, 10));
    return range(start, max, step);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map((n) => validate(parseInt(n, 10)));
    if (lo > hi) throw new RangeError(`Invalid range: ${expr}`);
    return range(lo, hi);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new SyntaxError(`Unexpected token in cron expression: "${expr}"`);
  return [validate(n)];
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );

  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  return fields.reduce<CronFields>((acc, field, i) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = parseField(parts[i], min, max);
    return acc;
  }, {} as CronFields);
}

