const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in segment: "${segment}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      start = clamp(s, min, max);
      end   = clamp(e, min, max);
      if (start > end) throw new RangeError(`Invalid range "${rangePart}": start > end`);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      end   = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) values.push(v);
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);
    if (start > end) throw new RangeError(`Invalid range "${segment}": start > end`);
    return range(start, end);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment.split(",").map((part) => {
      const v = parseInt(part.trim(), 10);
      if (isNaN(v)) throw new SyntaxError(`Invalid value "${part}" in list`);
      return clamp(v, min, max);
    });
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid cron segment: "${segment}"`);
  return [clamp(value, min, max)];
};

