  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clamp = (values: number[], min: number, max: number): number[] => {
  const invalid = values.find(v => v < min || v > max);
  if (invalid !== undefined) {
    throw new RangeError(`Value ${invalid} out of range [${min}, ${max}]`);
  }
  return values;
};

const parseSegment = (segment: string, { min, max }: FieldConfig): number[] => {
  // Step: */n or start-end/n
