      rangePart === "*"
        ? [min, max]
        : rangePart.includes("-")
        ? rangePart.split("-").map(Number)
        : [parseInt(rangePart, 10), max];
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in step: ${segment}`);
    clamp([start, end], min, max);
    return range(start, end).filter(v => (v - start) % step === 0);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: n-m
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
    return clamp(range(start, end), min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${segment}`);
