const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function rangeArray(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => i + min);
}

function clampToRange(values: number[], min: number, max: number): number[] {
  return [...new Set(values.filter((v) => v >= min && v <= max))].sort(
    (a, b) => a - b
  );
}

function parseField(field: string, min: number, max: number): number[] {
  // Wildcard
  if (field === "*") {
    return rangeArray(min, max);
  }

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range: ${rangePart}`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: ${rangePart}`);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return clampToRange(values, min, max);
  }

  // Comma-separated list (may include ranges within)
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = parts.flatMap((part) => parseField(part.trim(), min, max));
    return clampToRange(values, min, max);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${field}`);
    }
    if (start > end) {
      throw new Error(`Range start (${start}) must be <= end (${end})`);
    }
    return clampToRange(rangeArray(start, end), min, max);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron field value: ${field}`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}]`);
  }
  return [value];
}

export function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];
  const result = {} as CronExpression;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  // Normalize dayOfWeek: treat 7 as 0 (both = Sunday)
  if (result.dayOfWeek.includes(7)) {
    result.dayOfWeek = clampToRange(
      [...new Set([...result.dayOfWeek.map((d) => (d === 7 ? 0 : d))])],
      0,
      6
    );
  }

  return result;
}

