    const base = parseField(rangePart, field, min, max);
    return base.filter((_, i) => i % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${expr}" for field "${field}"`);
    }
    validateValue(start, min, max, field);
    validateValue(end, min, max, field);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in "${expr}" for field "${field}"`);
    }
    return expandRange(start, end);
  }

  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid token "${expr}" for field "${field}"`);
  }
  validateValue(value, min, max, field);
  return [value];
}

export default function parseCron(expression: string): CronExpression {
