  const fields = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];

  return fields.reduce<CronExpression>((acc, field, i) => {
    const [min, max] = FIELD_RANGES[field];
    acc[field] = parseField(parts[i], field, min, max);
    return acc;
