export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_RANGES: Record<FieldName, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function buildRange(start: number, end: number): number[] {
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}–${max}] in "${context}"`);
  }
}

function parseSingleField(token: string, min: number, max: number): number[] {
  // Comma-separated list — recurse on each part, then deduplicate
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap((part) => parseSingleField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step expression: */n  or  start-end/n  or  start/n
  if (token.includes("/")) {
    const slashIdx = token.lastIndexOf("/");
    const rangePart = token.slice(0, slashIdx);
    const step = parseInt(token.slice(slashIdx + 1), 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step in "${token}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      assertInRange(s, min, max, token);
      assertInRange(e, min, max, token);
      if (s > e) throw new Error(`Invalid range start > end in "${token}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base in "${token}"`);
      assertInRange(start, min, max, token);
      end = max;
    }

    const out: number[] = [];
    for (let i = start; i <= end; i += step) out.push(i);
    return out;
  }

  // Range: start-end
  if (token.includes("-")) {
    const dashIdx = token.indexOf("-");
    const start = parseInt(token.slice(0, dashIdx), 10);
    const end = parseInt(token.slice(dashIdx + 1), 10);

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in "${token}"`);
    assertInRange(start, min, max, token);
    assertInRange(end, min, max, token);
    if (start > end) throw new Error(`Range start > end in "${token}"`);

    return buildRange(start, end);
  }

  // Wildcard
  if (token === "*") return buildRange(min, max);

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num)) throw new Error(`Unrecognised token "${token}"`);
  assertInRange(num, min, max, token);
  return [num];
}

export default function parseCron(expression: string): CronExpression {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Cron expression must have exactly 5 fields; got ${fields.length}`);
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;
  const field = (raw: string, name: FieldName) =>
    parseSingleField(raw, ...FIELD_RANGES[name]);

  return {
    minute:     field(minuteRaw, "minute"),
    hour:       field(hourRaw,   "hour"),
    dayOfMonth: field(domRaw,    "dayOfMonth"),
    month:      field(monthRaw,  "month"),
    dayOfWeek:  field(dowRaw,    "dayOfWeek"),
  };
}

