const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function range(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      end = max;
    }

    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid step expression: "${segment}"`);
    }

    validateRange(start, end, min, max, segment);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range expression: "${segment}"`);
    }
    const [from, to] = parts.map(Number);
    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range values: "${segment}"`);
    }
    if (from > to) {
      throw new Error(`Range start ${from} exceeds end ${to} in "${segment}"`);
    }
    validateRange(from, to, min, max, segment);
    return range(from, to);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value: "${segment}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in "${segment}"`);
  }
  return [value];
}

function validateRange(
  from: number,
  to: number,
  min: number,
  max: number,
  original: string
): void {
  if (from < min || from > max || to < min || to > max) {
    throw new Error(
      `Values in "${original}" are out of range [${min}, ${max}]`
    );
  }
}

function parseField(field: string, config: FieldConfig): number[] {
  // Comma-separated list
  const segments = field.split(",");
  const allValues = new Set<number>();

  for (const segment of segments) {
    const values = parseSegment(segment.trim(), config);
    for (const v of values) allValues.add(v);
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

