};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clampToRange = (values: number[], min: number, max: number): number[] => {
  const filtered = values.filter(v => v >= min && v <= max);
  if (filtered.length !== values.length) {
    throw new RangeError(`Value out of range [${min}, ${max}]`);
  }
  return filtered;
};

const parseSegment = (segment: string, { min, max }: FieldConfig): number[] => {
  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    const start = base === "*" ? min : parseInt(base, 10);
    if (isNaN(start)) throw new Error(`Invalid step base: ${base}`);

    const values: number[] = [];
    for (let v = start; v <= max; v += step) values.push(v);
    return clampToRange(values, min, max);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start > end) throw new Error(`Range start exceeds end: ${segment}`);
    return clampToRange(range(start, end), min, max);
  }

  // Single value
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: ${segment}`);
  return clampToRange([value], min, max);
};

