      flattenObject(value as Record<string, unknown>, fullKey, result);
    } else {
      result[fullKey] = value;
    }
  }
  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const range = (start: number, end: number, step = 1): number[] => {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
};

const parseField = (field: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  const validate = (value: number, context: string): number => {
    if (!Number.isInteger(value) || value < min || value > max) {
      throw new RangeError(
        `Value ${value} out of range [${min}, ${max}] in "${context}"`
      );
    }
    return value;
  };

  // Comma-separated list — recurse on each part and deduplicate
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), config));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard with optional step: * or */step
  if (field.startsWith("*")) {
    if (field === "*") return range(min, max);
    const slashIdx = field.indexOf("/");
    if (slashIdx !== -1) {
      const step = Number(field.slice(slashIdx + 1));
      if (!Number.isInteger(step) || step < 1) {
        throw new TypeError(`Invalid step value in "${field}"`);
      }
      return range(min, max, step);
    }
    throw new TypeError(`Invalid wildcard expression "${field}"`);
  }

  // Range with optional step: start-end or start-end/step
  if (field.includes("-")) {
    const [rangePart, stepPart] = field.split("/");
    const [startStr, endStr] = (rangePart ?? "").split("-");
    const start = validate(Number(startStr), field);
    const end = validate(Number(endStr), field);
    if (start > end) {
      throw new RangeError(`Start ${start} > end ${end} in range "${field}"`);
    }
    const step = stepPart !== undefined ? Number(stepPart) : 1;
    if (!Number.isInteger(step) || step < 1) {
      throw new TypeError(`Invalid step value in "${field}"`);
    }
    return range(start, end, step);
  }

  // Bare number
  const num = Number(field);
  if (Number.isNaN(num)) {
    throw new TypeError(`Invalid cron field value "${field}"`);
  }
  return [validate(num, field)];
};

const parseCron = (expression: string): CronExpression => {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${parts.length} in expression "${expression}"`
    );
  }

  const [minutePart, hourPart, domPart, monthPart, dowPart] = parts as [
    string,
    string,
    string,
    string,
    string,
  ];

  return {
    minute:     parseField(minutePart, FIELD_CONFIGS.minute),
    hour:       parseField(hourPart,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domPart,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthPart,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowPart,    FIELD_CONFIGS.dayOfWeek),
  };
};

export default parseCron;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return (
    typeof value === "object" &&
    value !== null &&
    !Array.isArray(value) &&
    Object.getPrototypeOf(value) === Object.prototype
  );
}

function deepMerge<T extends Record<string, unknown>>(
  target: T,
  source: Partial<T>
): T {
  if (!isPlainObject(target) || !isPlainObject(source)) {
    return source as T ?? target;
  }

  const result: Record<string, unknown> = { ...target };

  for (const key of Object.keys(source)) {
    const targetVal = result[key];
    const sourceVal = source[key];

    if (Array.isArray(targetVal) && Array.isArray(sourceVal)) {
      result[key] = [...targetVal, ...sourceVal];
    } else if (isPlainObject(targetVal) && isPlainObject(sourceVal)) {
      result[key] = deepMerge(targetVal, sourceVal);
    } else if (key in source) {
      result[key] = sourceVal;
    }
  }

  return result as T;
}

export default deepMerge;

